sql:
SELECT spacecraft_name
FROM norad_catalog
WHERE status = 'active';

SELECT COUNT(norad_id) AS operational_spacecraft_count
FROM norad_catalog
WHERE status = 'active';

SELECT norad_id
FROM spacecraft_data
WHERE encryption_status = 'encrypted';

SELECT frequency
FROM spacecraft_data
ORDER BY frequency DESC;

SELECT norad_id
FROM norad_catalog
WHERE orbit_altitude = (SELECT MAX(orbit_altitude) FROM norad_catalog);

external_knowledge:
- 'Processed' data refers to data that has completed all necessary data processing steps and is ready for use;
- 'View' access type indicates that the data has been accessed for viewing purposes, not for downloading or processing;
- 'Average signal strength' is calculated as the mean of the signal strengths for the data entries.

- 'Whispers from the celestial traveler' refers to the signal strength of data entries for the spacecraft with Norad ID 1234;
- 'Ears of the watchers' refers to the receivers with the callsigns that match the source of the data;
- 'Latest version of their listening devices' refers to the specific hardware version 2.3.4 and software version 5.6.7;
- Only groups of data with more than one entry are considered in the calculation of the average signal strength.

sql:
SELECT data_type, MAX(signal_strength) AS max_signal_strength
FROM spacecraft_data
GROUP BY data_type;

